@staticmethod
def _resolve_reference_price(order: Order) -> float | None:
    '''FTS-RE-008: 参照価格を order.price → context_snapshot.price → order.fill_price の順で解決する共通ヘルパ。
    TotalExposure / Margin 双方で使い fail-safe ポリシーを統一する。'''
    if order.price is not None and order.price > 0:
        return float(order.price)
    snap = order.context_snapshot
    if snap is not None:
        snap_price = getattr(snap, 'price', None)
        if snap_price is None and isinstance(snap, dict):
            snap_price = snap.get('price')
        if isinstance(snap_price, (int, float)) and snap_price > 0:
            return float(snap_price)
    if order.fill_price is not None and order.fill_price > 0:
        return float(order.fill_price)
    return None

